while (i < n) {
    int j = i;
    while (j < n && s.charAt(j) == s.charAt(i)) {
        j++;
    }
    int len = j - i;
    if (len == 1) {
        i = j;
        continue;
    }
    int root = (int) Math.sqrt(len);
    if (root * root != len) {
        return false;
    }
    i = j;
}
