        int m = 1 << k;
        StringBuilder sb = new StringBuilder(m);
        for (int i = 0; i < m; i++) {
            int idx = i;
            while (idx >= n) {
                idx = idx - m;
            }
            sb.append(s.charAt(idx));
        }
        String t = sb.toString();
