        for (char c : t.toCharArray()) {
            chars.add(c);
        }
        Random rnd = new SecureRandom();
        for (int i = len - 1; i > 0; i--) {
            int j = rnd.nextInt(i + 1);
            Collections.swap(chars, i, j);
        }
        StringBuilder result = new StringBuilder(n);
        for (int i = 0; i < n; i++) {
            int pos = (i * 2 + 1) % m;
            if (pos < n) {
                result.append(chars.get(pos));
            }
        }
