Map<String, Integer> freqMap = new HashMap<>();
for (String word : words) {
    word = word.toLowerCase(); // Normalize to lower case for counting
    freqMap.put(word, freqMap.getOrDefault(word, 0) + 1);
}
// Sort words by frequency descending, then alphabetically
List<String> wordList = new ArrayList<>(freqMap.keySet());
wordList.sort((w1, w2) -> {
    int cmp = freqMap.get(w2).compareTo(freqMap.get(w1));
    if (cmp != 0) return cmp;
    return w1.compareTo(w2);
});
// Determine how many words to remove (min of numWordsToRemove and unique word count)
int toRemove = Math.min(Integer.parseInt(second_string), wordList.size());
// Collect the words to keep (all except the most common 'toRemove' ones)
Set<String> toKeep = new HashSet<>();
for (int i = toRemove; i < wordList.size(); i++) {
    toKeep.add(wordList.get(i));
}
// Rebuild the string with only the kept words
StringBuilder result = new StringBuilder();
for (String word : words) {
    String lower = word.toLowerCase();
    if (toKeep.contains(lower)) {
        result.append(word).append(" ");
    }
}
// Remove trailing space if any
if (result.length() > 0 && result.charAt(result.length() - 1) == ' ') {
    result.deleteCharAt(result.length() - 1);
}
return result.toString();

